parameters.new_string:
async send(
  params: {
    type: NotificationType;
    recipient: string;
    subject: string;
    body: string;
    metadata?: Record<string, unknown>;
    channel?: NotificationChannel;
    userId?: string;
  },
): Promise<NotificationResult | undefined> {
  // Chain onto the per-recipient queue to guarantee delivery order.
  // Each recipient's notifications are serialized so that e.g. "order placed"
  // is always delivered before "payment confirmed" for the same user.
  const previous = this.sendQueues.get(params.recipient) ?? Promise.resolve(undefined);
  const current = previous.then(
    () => this.doSend(params),
    () => this.doSend(params),
  );
  this.sendQueues.set(params.recipient, current);
  return current;
}

/**
 * Internal send implementation — performs preference checks, adapter dispatch,
 * and history recording. Called from send() via the per-recipient queue.
 */
private async doSend(
  params: {
    type: NotificationType;
    recipient: string;
    subject: string;
    body: string;
    metadata?: Record<string, unknown>;
    channel?: NotificationChannel;
    userId?: string;
  },
): Promise<NotificationResult | undefined> {
  const channel = params.channel ?? this.defaultChannel;

  // Check user preferences if a preferences service is configured
  const userId = params.userId ?? (params.metadata?.['userId'] as string | undefined);
  if (userId && this.preferencesService) {
    if (!this.preferencesService.shouldSendNotification(userId, params.type, channel)) {
      this.logger.info(
        `Notification suppressed for user ${userId}: type=${params.type}, channel=${channel} (user preference)`,
      );
      return undefined;
    }
  }
  const payload: NotificationPayload = {
    id: generateNotificationId(),
    type: params.type,
    recipient: params.recipient,
    subject: params.subject,
    body: params.body,
    metadata: params.metadata,
    createdAt: new Date(),
  };

  const adapter = this.adapters.get(channel);
  let result: NotificationResult | undefined;

  if (adapter) {
    result = await adapter.send(payload);
  }

  const notification: Notification = {
    id: payload.id,
    type: payload.type,
    recipient: payload.recipient,
    subject: payload.subject,
    body: payload.body,
    channel,
    metadata: payload.metadata,
    sentAt: payload.createdAt,
    delivered: result?.success ?? true,
    error: result?.error,
  };
  this.notifications.push(notification);

  if (this.historyService) {
    this.historyService.record(notification);
  }

  this.logger.info(`Notification ${notification.id} sent to ${params.recipient} via ${channel}`);

  return result;
}

